-- ----------------------------
-- Table structure for message
-- ----------------------------
DROP TABLE IF EXISTS `message`;
CREATE TABLE `message`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '消息标题（可为空；用于通知类消息的短标题）',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '消息内容（正文）',
  `message_type` enum('SYSTEM','TASK','DIRECT') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'SYSTEM' COMMENT '消息类型（SYSTEM/TASK/DIRECT）',
  `sender_id` int NULL DEFAULT NULL COMMENT '发送者用户ID（系统消息可为空）',
  `receiver_id` int NOT NULL COMMENT '接收者用户ID',
  `is_read` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否已读',
  `read_time` datetime(3) NULL DEFAULT NULL COMMENT '已读时间（首次标记已读时写入）',
  `extra` json NULL COMMENT '扩展数据（可选；用于携带业务跳转信息等，JSON）',
  `create_time` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '创建时间',
  `update_time` datetime(3) NOT NULL COMMENT '更新时间',
  `deleted_at` datetime(3) NULL DEFAULT NULL COMMENT '软删除时间（为空表示未删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_message_receiver_read_time`(`receiver_id` ASC, `is_read` ASC, `create_time` ASC) USING BTREE,
