-- ----------------------------
-- Table structure for task
-- ----------------------------
DROP TABLE IF EXISTS `task`;
CREATE TABLE `task`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `project_id` int NOT NULL,
  `org_id` int NULL DEFAULT NULL,
  `version` int NOT NULL DEFAULT 0,
  `parent_id` int NULL DEFAULT NULL,
  `type` enum('FEATURE','BUG','CHORE','ENHANCEMENT') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'FEATURE',
  `priority` enum('P0','P1','P2','P3') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'P2',
  `due_date` datetime(3) NULL DEFAULT NULL,
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `status` enum('PENDING','IN_PROGRESS','SELF_TESTING','QA_REVIEW','REJECTED','COMPLETED','PAUSED','CANCELLED') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDING',
  `manager_id` int NULL DEFAULT NULL,
  `main_assignee_id` int NULL DEFAULT NULL,
  `tester_id` int NULL DEFAULT NULL,
  `estimated_hours` double NULL DEFAULT NULL,
  `actual_hours` double NULL DEFAULT NULL,
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  `work_domain` enum('SOFTWARE_DEVELOPMENT','PRODUCT_DESIGN','OPERATIONS_SUPPORT','DATA_ANALYTICS','GENERAL') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'GENERAL',
  `qaRejectReason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `acceptedAt` datetime(3) NULL DEFAULT NULL,
  `baseScore` double NULL DEFAULT NULL,
  `baseScoreSource` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'AUTO',
  `suggestedBaseScore` double NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `task_projectId_fkey`(`project_id` ASC) USING BTREE,
  INDEX `task_parentId_fkey`(`parent_id` ASC) USING BTREE,
  INDEX `task_managerId_fkey`(`manager_id` ASC) USING BTREE,
  INDEX `task_mainAssigneeId_fkey`(`main_assignee_id` ASC) USING BTREE,
  INDEX `task_testerId_fkey`(`tester_id` ASC) USING BTREE,
  CONSTRAINT `task_mainAssigneeId_fkey` FOREIGN KEY (`main_assignee_id`) REFERENCES `user` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `task_managerId_fkey` FOREIGN KEY (`manager_id`) REFERENCES `user` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `task_parentId_fkey` FOREIGN KEY (`parent_id`) REFERENCES `task` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `task_projectId_fkey` FOREIGN KEY (`project_id`) REFERENCES `project` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `task_testerId_fkey` FOREIGN KEY (`tester_id`) REFERENCES `user` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '任务表' ROW_FORMAT = Dynamic;

