-- ----------------------------
-- Table structure for upload_session
-- ----------------------------
DROP TABLE IF EXISTS `upload_session`;
CREATE TABLE `upload_session`  (
  `id` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `file_name` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `mime_type` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `total_size` int NOT NULL,
  `chunk_size` int NOT NULL,
  `total_chunks` int NOT NULL,
  `user_id` int NOT NULL,
  `status` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `attachment_id` int NULL DEFAULT NULL,
  `expires_at` datetime(3) NOT NULL,
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `upload_session_attachmentId_key`(`attachment_id` ASC) USING BTREE,
  INDEX `upload_session_userId_idx`(`user_id` ASC) USING BTREE,
  CONSTRAINT `upload_session_attachmentId_fkey` FOREIGN KEY (`attachment_id`) REFERENCES `attachment` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `upload_session_userId_fkey` FOREIGN KEY (`user_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '分片上传会话：合并完成后写入 attachmentId' ROW_FORMAT = Dynamic;

